msg.headers = { 'content-type':'application/json; charset=utf-8', 'cache-control':'no-store' };
msg.payload = flow.get('mavlinkAiParamBrowser') || { params: [], message: 'No parameter operation completed yet.' };
return msg;

const body = msg.payload && typeof msg.payload === 'object' ? msg.payload : {};
const action = String(body.action || 'list').toLowerCase();
const respond = (statusCode, payload) => ({ _msgid:msg._msgid, req:msg.req, res:msg.res, statusCode, headers:{'content-type':'application/json; charset=utf-8','cache-control':'no-store'}, payload });
if (!['list','read','set'].includes(action)) return [null, respond(400,{message:'action must be list, read, or set'})];
const paramId = String(body.param_id || '').trim().toUpperCase();
if ((action==='read'||action==='set') && !/^[A-Z0-9_]{1,16}$/.test(paramId)) return [null, respond(400,{message:'param_id must be 1-16 letters, digits, or underscores'})];
if (action==='set' && body.confirm !== 'SET') return [null, respond(400,{message:'Type SET in the confirmation field before changing a parameter.'})];
if (action==='set' && !Number.isFinite(Number(body.param_value))) return [null, respond(400,{message:'param_value must be a finite number'})];
const workflow = Object.assign({}, msg, { payload:{ action, param_id:paramId, param_value:action==='set'?Number(body.param_value):undefined, param_type:body.param_type || 'auto' } }); delete workflow.req; delete workflow.res;
return [workflow, respond(202,{message:`${action} request accepted; results will appear shortly`})];

const state = flow.get('mavlinkAiParamBrowser') || { params: [] };
const p = msg.payload || {};
if (msg.topic === 'param/list' && Array.isArray(p.params)) state.params = p.params;
if ((msg.topic === 'param/value' || msg.topic === 'param/set') && p.param_id) { const index=state.params.findIndex(x=>String(x.param_id).toUpperCase()===String(p.param_id).toUpperCase()); if(index>=0)state.params[index]=p;else state.params.push(p); }
state.message = `${msg.topic || 'parameter'} completed`; state.progress = ''; state.updatedAt = Date.now(); flow.set('mavlinkAiParamBrowser',state);
return msg;
